@startuml
!theme plain

' Package structure
package "androidx" {
  package "recyclerview" {
    package "widget" {
      class "RecyclerView" {
        <<interface>>
        "C" Adapter
      }
    }
  }
}

package "com" {
  package "example" {
    package "simple_chat" {
      package "recycler_view_adapter" {
        class "ChatAdapter" {
          <<class>>
          "C" ChatAdapter
          "o" mData : List<RecordInfo>
          "o" headerOfMy : Bitmap
          "o" headerOfSystem : Bitmap
          "o" intent : Intent
          "o" mapOfImage : HashMap<String, Bitmap>
          "o" settingInfo : SharedPreferences
          "o" ChatAdapter()
          "o" getItemCount()
          "o" getItemViewType()
          "o" onBindViewHolder()
          "o" onCreateViewHolder()
          "o" updateHeader()
          "o" setHeaderImage()
        }
      }
    }
  }
}

' Relationships
"ChatAdapter" ..> "Adapter" : implements
"ChatAdapter" o-- "MyService" : binder

class "MyService" {
  <<class>>
  "C" MusicInfoBinder
}

@enduml
